import React, { useState, useEffect } from "react";
import api from "../api/api";
import { 
  FaChartLine, 
  FaBox, 
  FaMoneyBillWave, 
  FaCalendarAlt, 
  FaFileDownload 
} from "react-icons/fa";

export default function Reportes() {
  const [datosReporte, setDatosReporte] = useState({
    ventasPorMes: [],
    productosMasVendidos: [],
    resumenGeneral: { totalVentas: 0, totalGanancia: 0, totalProductos: 0 }
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    cargarReportes();
  }, []);

  const cargarReportes = async () => {
    try {
      setLoading(true);
      const res = await api.get("/reportes");
      
      // ✅ NORMALIZACIÓN: Aseguramos que si algo falla en el backend, el front tenga arrays vacíos
      setDatosReporte({
        ventasPorMes: res.data?.ventasPorMes || [],
        productosMasVendidos: res.data?.productosMasVendidos || [],
        resumenGeneral: res.data?.resumenGeneral || { totalVentas: 0, totalGanancia: 0, totalProductos: 0 }
      });
    } catch (error) {
      console.error("❌ Error al cargar reportes:", error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return (
    <div className="text-center mt-5">
      <div className="spinner-border text-primary"></div>
      <p className="mt-2 text-muted">Generando estadísticas...</p>
    </div>
  );

  return (
    <div className="container-fluid p-4">
      <div className="card border-0 shadow-sm p-4 mb-4 bg-white rounded-4">
        <div className="d-flex justify-content-between align-items-center">
          <h3 className="fw-bold m-0 text-dark">
            <FaChartLine className="me-2 text-primary" /> Reportes y Estadísticas
          </h3>
          <button className="btn btn-outline-primary fw-bold" onClick={() => window.print()}>
            <FaFileDownload className="me-2"/> Exportar PDF
          </button>
        </div>
      </div>

      {/* Tarjetas de Resumen */}
      <div className="row mb-4 g-3">
        <div className="col-md-4">
          <div className="card border-0 shadow-sm rounded-4 p-3 bg-primary text-white h-100">
            <div className="d-flex align-items-center">
              <FaMoneyBillWave className="fs-1 me-3 opacity-50" />
              <div>
                <p className="mb-0 small opacity-75">Ganancia Total</p>
                <h3 className="fw-bold mb-0">
                  ${Number(datosReporte.resumenGeneral?.totalGanancia || 0).toFixed(2)}
                </h3>
              </div>
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card border-0 shadow-sm rounded-4 p-3 bg-success text-white h-100">
            <div className="d-flex align-items-center">
              <FaCalendarAlt className="fs-1 me-3 opacity-50" />
              <div>
                <p className="mb-0 small opacity-75">Ventas Totales</p>
                <h3 className="fw-bold mb-0">{datosReporte.resumenGeneral?.totalVentas || 0}</h3>
              </div>
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card border-0 shadow-sm rounded-4 p-3 bg-info text-white h-100">
            <div className="d-flex align-items-center">
              <FaBox className="fs-1 me-3 opacity-50" />
              <div>
                <p className="mb-0 small opacity-75">Productos Activos</p>
                <h3 className="fw-bold mb-0">{datosReporte.resumenGeneral?.totalProductos || 0}</h3>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="row">
        {/* Tabla Ventas por Mes */}
        <div className="col-md-6 mb-4">
          <div className="card border-0 shadow-sm rounded-4 h-100">
            <div className="card-header bg-white border-0 py-3">
              <h5 className="fw-bold mb-0">📈 Ventas Mensuales</h5>
            </div>
            <div className="card-body">
              <table className="table table-hover align-middle">
                <thead className="table-light">
                  <tr>
                    <th>Mes</th>
                    <th className="text-end">Monto</th>
                  </tr>
                </thead>
                <tbody>
                  {/* ✅ PROTECCIÓN: Usamos v?.mes para que no crashee si un objeto está mal */}
                  {datosReporte.ventasPorMes.length > 0 ? (
                    datosReporte.ventasPorMes.map((v, idx) => (
                      <tr key={idx}>
                        <td className="fw-bold">{v?.mes || "Sin nombre"}</td>
                        <td className="text-end text-success fw-bold">
                          ${Number(v?.total || 0).toFixed(2)}
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr><td colSpan="2" className="text-center py-4 text-muted">No hay datos mensuales disponibles</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Tabla Productos más vendidos */}
        <div className="col-md-6 mb-4">
          <div className="card border-0 shadow-sm rounded-4 h-100">
            <div className="card-header bg-white border-0 py-3">
              <h5 className="fw-bold mb-0">🏆 Top Productos</h5>
            </div>
            <div className="card-body">
              <table className="table table-hover align-middle">
                <thead className="table-light">
                  <tr>
                    <th>Producto</th>
                    <th className="text-center">Ventas</th>
                  </tr>
                </thead>
                <tbody>
                  {datosReporte.productosMasVendidos.length > 0 ? (
                    datosReporte.productosMasVendidos.map((p, idx) => (
                      <tr key={idx}>
                        <td>{p?.nombre || "Producto desconocido"}</td>
                        <td className="text-center fw-bold">{p?.cantidadVendido || 0}</td>
                      </tr>
                    ))
                  ) : (
                    <tr><td colSpan="2" className="text-center py-4 text-muted">Aún no hay ventas registradas</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
